const grpcClient = new grpcService.YourService('localhost:50051', grpc.credentials.createInsecure());

app.post('/your-api-endpoint', (req, res) => {
    const userAgent = req.headers['user-agent'];
    const xForwardedFor = req.headers['x-forwarded-for'];
    const customHeaders = req.headers['custom-header'];
  
    const meta = new metadata();
    if (userAgent) {
        meta.add('user-agent', userAgent);
    }
    if (xForwardedFor) {
        meta.add('x-forwarded-for', xForwardedFor);
    }
    if (customHeaders) {
        meta.add('custom-header', customHeaders);
    }

    grpcClient.yourRpcMethod(req.body, meta, (error, response) => {
        if (error) {
            res.status(500).send(error);
        } else {
            res.status(200).send(response);
        }
    });
});

const PORT = process.env.PORT || 3000;
